#define _cls MicroMessengerAppDelegate
#define _sel application_performActionForShortcutItem_completionHandler_
INS_HOOK_DECL(void, _cls, _sel, (id zelf, SEL sel, UIApplication *application, UIApplicationShortcutItem *shortcutItem, void (^completionHandler)(BOOL))) {
    NSString *contactSupport = [[[NSBundle mainBundle] bundleIdentifier] stringByAppendingString:@".contactSupport"];
    NSString *modifySettings = [[[NSBundle mainBundle] bundleIdentifier] stringByAppendingString:@".modifySettings"];
    if ([shortcutItem.type isEqualToString:contactSupport] || [shortcutItem.type isEqualToString:modifySettings]) {
        dispatch_async(dispatch_get_main_queue(), ^{
            UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"提示" message:@"当前处于微信环境，请点击【关闭APP】或上滑关闭应用后重试。" preferredStyle:UIAlertControllerStyleAlert];
            UIAlertAction *okAction = [UIAlertAction actionWithTitle:@"取消" style:UIAlertActionStyleDefault handler:nil];
            UIAlertAction *closeAction = [UIAlertAction actionWithTitle:@"关闭App" style:UIAlertActionStyleDestructive handler:^(UIAlertAction * _Nonnull action) {
                exit(0);
            }];
            [alert addAction:okAction];
            [alert addAction:closeAction];
            [[WBAppManager getUIApplicationCurrentViewController] presentViewController:alert animated:YES completion:nil];
        });

        if (completionHandler) {
            completionHandler(YES); // 告诉系统我们已经处理了这个快捷操作
        }
    }
    return oldinsfn(_cls, _sel)(zelf, sel, application, shortcutItem, completionHandler);
}
#undef _sel
#undef _cls

