@implementation demoSceneDelegate

- (void)scene:(UIScene *)scene
        willConnectToSession:(UISceneSession *)session
      options:(UISceneConnectionOptions *)connectionOptions  API_AVAILABLE(ios(13.0)){

    on_scene_willConnectToSession_options_(session, connectionOptions);
    if (vapp_is_running()) {
        return;
    }

    NSLog(@"demoSceneDelegate Running");
    // 设置根窗口
    UIWindowScene *windowScene = (UIWindowScene *)scene;
    UIWindow *window = [[UIWindow alloc] initWithWindowScene:windowScene];
    window.rootViewController = [[[[WBAppManager sharedManager] getRootViewControllerClass] alloc] init];
    // window.rootViewController = [[WBLaunchViewController alloc] init];
    [window makeKeyAndVisible];
    _window = window;

    // 这里为了使用SVProgressHUD，要在appDelegate里创建window属性并赋值
    [UIApplication sharedApplication].delegate.window = window;

    // 检查是否通过 Quick Action 冷启动
    if (connectionOptions.shortcutItem) {
        self.stashedShortcutItem = connectionOptions.shortcutItem;
    }

    // 储存 url scheme, 等 mainVC 加载完.
    NSURL *url = [self getURLSchemeFromURLContents:connectionOptions.URLContexts];
    [WBAppManager sharedManager].stashedURLScheme = url;

    NSUserActivity *userActivity = connectionOptions.userActivities.allObjects.firstObject;
