- (void)viewDidAppear:(BOOL)animated {
    // 获取 SceneDelegate
    UIWindowScene *windowScene = (UIWindowScene *)[UIApplication sharedApplication].connectedScenes.anyObject;
    demoSceneDelegate *sceneDelegate = (demoSceneDelegate *)windowScene.delegate;
    if (sceneDelegate.stashedShortcutItem) {
        [self handleShortcutItem:sceneDelegate.stashedShortcutItem];
        sceneDelegate.stashedShortcutItem = nil;
    }

    NSURL *stashedURLScheme = [WBAppManager sharedManager].stashedURLScheme;
    if (stashedURLScheme) {
        [WBAppManager sharedManager].stashedURLScheme = nil;
        [[WBAppManager sharedManager] performURLScheme:stashedURLScheme];
    }
    WBBaseActionModel *stashedAction = [WBAppManager sharedManager].stashedAction;
    if (stashedAction) {
        [WBAppManager sharedManager].stashedAction = nil;
        [stashedAction executeWithDefaultHandler:nil];
    }
    [self tryPostAutoOpenNotification];
}


#pragma mark - short cut item

- (void)handleShortcutItem:(UIApplicationShortcutItem *)shortcutItem {
    NSString *contactSupport = [[[NSBundle mainBundle] bundleIdentifier] stringByAppendingString:@".contactSupport"];
    if ([shortcutItem.type isEqualToString:contactSupport]) {
        dispatch_async(dispatch_get_main_queue(), ^{
            UINavigationController *targetNavController = nil;
            UITabBarController *tabBarController = (UITabBarController *)self;
            UIViewController *selectedVC = tabBarController.selectedViewController;
            if ([selectedVC isKindOfClass:[UINavigationController class]]) {
                targetNavController = (UINavigationController *)selectedVC;
            } else if (selectedVC.navigationController) {
                targetNavController = selectedVC.navigationController;
            }

            WBFeedbackViewController *feedbackVC = [[WBFeedbackViewController alloc] init];
            [targetNavController pushViewController:feedbackVC animated:YES];
        });
    }
}


#pragma mark - setupUI

- (void)setupUI {
    [self setUpAppearence];
    [self addChildViewControllers];
}

// 添加所有子控制器
- (void)addChildViewControllers {
    [self addChildViewController:[[WBSubHomeViewController alloc] init] navTitle:NSLocalizedString(@"首页", nil) tabTitle:NSLocalizedString(@"首页", nil) tabImage:@"subMain_home"];
    [self addChildViewController:[[WBSubMineViewController alloc] init] navTitle:NSLocalizedString(@"我的", nil) tabTitle:NSLocalizedString(@"我的", nil) tabImage:@"subMain_mine"];
}

- (void)addChildViewController:(UIViewController *)vc navTitle:(NSString *)navTitle tabTitle:(NSString *)tabTitle tabImage:(NSString *)tabImage {
    // 设置标题 - 由内至外设置的
    vc.title = navTitle;
    // 设置图像
    vc.tabBarItem.image = [[UIImage imageNamed:tabImage] imageWithRenderingMode:UIImageRenderingModeAlwaysOriginal];
    vc.tabBarItem.selectedImage = [[UIImage imageNamed:[tabImage stringByAppendingString:@"_selected"]] imageWithRenderingMode:UIImageRenderingModeAlwaysOriginal];
    // 导航控制器
    UINavigationController *navVc = [[WBNavigationController alloc] initWithRootViewController:vc];
    navVc.tabBarItem.title = tabTitle;
    [self addChildViewController:navVc];
}

// 设置全局外观
- (void)setUpAppearence {
    [self setUpTabBar];
    [self setUpHUD];
}

- (void)setUpTabBar {
    // 设置tabBar的样式
    UITabBar *tabBar = self.tabBar;
    tabBar.translucent = NO;
    // 1> item选中时的渲染颜色
    tabBar.tintColor = RGB(64, 99, 231);
    // 2> item未选中时的渲染颜色
    if (@available(iOS 10.0, *)) {
        tabBar.unselectedItemTintColor = UIColorHex(666666);
    }
    if (@available(iOS 13.0, *)) {
        UITabBarAppearance *tabBarAppearence = [[UITabBarAppearance alloc] init];
        // 3> tabBar的颜色
        tabBarAppearence.backgroundColor = WBColorHex(0xFFFFFF);
        tabBar.standardAppearance = tabBarAppearence;
        if (@available(iOS 15.0, *)) {
            SEL sel = NSSelectorFromString(@"setScrollEdgeAppearance:");
            IMP imp = [tabBar methodForSelector:sel];
            void (*pFunc)(id, SEL, UITabBarAppearance *) = (void *)imp;
            pFunc(tabBar, sel, tabBarAppearence);
        }
    } else {
        // 3> tabBar的颜色
        tabBar.barTintColor = [UIColor whiteColor];
        // 4> 去除分割线
        tabBar.shadowImage = [UIImage new];
        tabBar.backgroundImage = [UIImage new];
    }
}

- (void)setUpHUD {
    [SVProgressHUD setBackgroundColor:RGBA(0, 0, 0, 0.5)];
    [SVProgressHUD setFont:[UIFont fontWithName:@"PingFang SC" size:14]];
    [SVProgressHUD setForegroundColor:[UIColor whiteColor]];
    [SVProgressHUD setMinimumSize:CGSizeMake(200, 120)];
    [SVProgressHUD setCornerRadius:15];
    [SVProgressHUD setMaximumDismissTimeInterval:0.8];
}


#pragma mark - notifications

- (void)tryPostAutoOpenNotification {
    if (self.hasPostedAutoOpenSessionNotification) return;
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.5 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
        if (self.hasPostedAutoOpenSessionNotification) return;
        UIViewController *selectedVC = self.selectedViewController;
        BOOL isSubHomeVisible = NO;
        if ([selectedVC isKindOfClass:[UINavigationController class]]) {
            UIViewController *visible = ((UINavigationController *)selectedVC).visibleViewController;
            isSubHomeVisible = [visible isKindOfClass:[WBSubHomeViewController class]];
        } else {
            isSubHomeVisible = [selectedVC isKindOfClass:[WBSubHomeViewController class]];
        }
        if (!isSubHomeVisible) return;
        self.hasPostedAutoOpenSessionNotification = YES;
        [[NSNotificationCenter defaultCenter] postNotificationName:WBShouldAutoOpenSessionNotification object:nil];
    });
}


@end

