- (void)exportOperationTraceFile {
    NSURL *traceFileURL = [WBOperationTraceRecorder traceFileURL];
    if (![[NSFileManager defaultManager] fileExistsAtPath:traceFileURL.path]) {
        [SVProgressHUD showInfoWithStatus:@"暂无操作日志"];
        return;
    }
    UIViewController *presentingVC = [WBAppManager getUIApplicationCurrentViewController];
    if (!presentingVC) {
        presentingVC = [WBAppManager getUIApplicationRootViewController];
    }
    if (!presentingVC) {
        [SVProgressHUD showErrorWithStatus:@"无法导出操作日志"];
        return;
    }
    UIActivityViewController *activityVC = [[UIActivityViewController alloc] initWithActivityItems:@[traceFileURL] applicationActivities:nil];
    if (activityVC.popoverPresentationController) {
        activityVC.popoverPresentationController.sourceView = presentingVC.view;
        activityVC.popoverPresentationController.sourceRect = CGRectMake(CGRectGetMidX(presentingVC.view.bounds), CGRectGetMidY(presentingVC.view.bounds), 1, 1);
    }
    [presentingVC presentViewController:activityVC animated:YES completion:nil];
}

- (void)uploadCrashLogs {
    // upload crash logs获取崩溃日志文件的路径。
    NSString *crashReportFilePath = [WBStorageManager sharedManager].crashReportFilePath;
    if ([[NSFileManager defaultManager] fileExistsAtPath:crashReportFilePath]) {// 检查崩溃日志文件是否存在。
        NSURL *crashReportFileURL = [NSURL fileURLWithPath:crashReportFilePath];// 将崩溃日志文件的路径转换为NSURL对象。
        NSParameterAssert(crashReportFileURL);// 使用NSParameterAssert确保crashReportFileURL不为nil，因为下一步需要这个URL。
        // 使用WBNetworkManager的postLogsWithFileName:fileURL:callback:方法异步上传崩溃日志。
        [[WBNetworkManager defaultManager] postLogsWithFileName:@"crash" fileURL:crashReportFileURL callback:^(id  _Nullable json, NSError * _Nullable error) {// 使用NSParameterAssert确保json和error只有一个是非nil的，因为上传操作应该只返回一个结果。
            NSParameterAssert(json == nil ^ error == nil);
            if (!error) {// 如果上传成功且没有错误，则尝试删除崩溃日志文件。
                NSError *err = nil;
                // clear file content
                [NSFileManager.defaultManager removeItemAtPath:crashReportFilePath error:&err];// 从文件系统中删除崩溃日志文件。
                NSParameterAssert(!err);// 使用NSParameterAssert确保在删除文件时没有发生错误。
            }
        }];
    }
}

// 上传客户端本地的路由执行日志
- (void)uploadRouteLogs {
    NSString *routeReportFilePath = [WBStorageManager sharedManager].routeLogFilePath;
    if ([[NSFileManager defaultManager] fileExistsAtPath:routeReportFilePath]) {
        NSURL *routeReportFileURL = [NSURL fileURLWithPath:routeReportFilePath];
        NSParameterAssert(routeReportFileURL);
        [[WBNetworkManager defaultManager] postRouteLogsWithFileURL:routeReportFileURL callback:^(id  _Nullable json, NSError * _Nullable error) {
            if (error) {
                NSLog(@"路由日志上传失败：%@", error.localizedDescription);
            } else {
                // 成功上传后清理日志
                [NSFileManager.defaultManager removeItemAtPath:routeReportFilePath error:&error];
            }
        }];
    }
}

