lelele，我建议你先只改两处，别铺太大：

## 改动点

### 1）修 `presenter` 获取
把 `/Users/liuyifu/Documents/Bface/weihe/WeBox/WeBox/Core/Service/WBAppManager.m` 里这 3 个方法替换掉：

```objc
+ (UIWindow*)getUIApplicationKeywindow {
    UIWindow *window = nil;
    if (@available(iOS 13.0, *)) {
        for (UIScene *scene in UIApplication.sharedApplication.connectedScenes) {
            if (![scene isKindOfClass:[UIWindowScene class]]) continue;
            UIWindowScene *windowScene = (UIWindowScene *)scene;
            if (windowScene.activationState != UISceneActivationStateForegroundActive &&
                windowScene.activationState != UISceneActivationStateForegroundInactive) {
                continue;
            }

            for (UIWindow *item in windowScene.windows.reverseObjectEnumerator) {
                if (item.isKeyWindow) {
                    return item;
                }
            }

            for (UIWindow *item in windowScene.windows.reverseObjectEnumerator) {
                if (!item.hidden && item.alpha > 0.01 && item.windowLevel == UIWindowLevelNormal) {
                    return item;
                }
            }

            if (!window && windowScene.windows.count > 0) {
                window = windowScene.windows.firstObject;
            }
        }
    }

#pragma clang diagnostic push
#pragma clang diagnostic ignored "-Wdeprecated-declarations"
    if (!window) {
        window = UIApplication.sharedApplication.keyWindow;
    }
#pragma clang diagnostic pop

    if (!window &&
        [UIApplication.sharedApplication.delegate respondsToSelector:@selector(window)]) {
        window = UIApplication.sharedApplication.delegate.window;
    }

    return window;
}

+ (UIViewController *)getUIApplicationRootViewController {
    return [WBAppManager getUIApplicationKeywindow].rootViewController;
}

+ (UIViewController *)getUIApplicationCurrentViewController {
    UIViewController *currentVC = [WBAppManager getUIApplicationRootViewController];

    while (currentVC) {
        UIViewController *nextVC = nil;

        if (currentVC.presentedViewController) {
            nextVC = currentVC.presentedViewController;
        } else if ([currentVC isKindOfClass:[UINavigationController class]]) {
            UINavigationController *nav = (UINavigationController *)currentVC;
            nextVC = nav.visibleViewController ?: nav.topViewController;
        } else if ([currentVC isKindOfClass:[UITabBarController class]]) {
            nextVC = ((UITabBarController *)currentVC).selectedViewController;
        }

        if (!nextVC || nextVC == currentVC) {
            break;
        }
        currentVC = nextVC;
    }

    return currentVC;
}
```

